    #[test]
    fn test_state_manifest_with_partition_bounds_roundtrip() {
        let mut min_values = HashMap::new();
        min_values.insert("date".to_string(), "2024-01-01".to_string());
        let mut max_values = HashMap::new();
        max_values.insert("date".to_string(), "2024-12-31".to_string());

        let manifest = StateManifest {
            version: 1,
            manifests: vec![ManifestInfo {
                path: "manifests/manifest-aabbccdd.avro".to_string(),
                file_count: 10,
                partition_bounds: Some(PartitionBounds {
                    min_values: min_values.clone(),
                    max_values: max_values.clone(),
                }),
                min_added_at_version: 1,
                max_added_at_version: 1,
                tombstone_count: 0,
                live_entry_count: 10,
            }],
            partition_bounds: None,
            created_time: 1700000000000,
            total_file_count: 10,
            format: "avro-state".to_string(),
            protocol_json: None,
            metadata: None,
            schema_registry: HashMap::new(),
            tombstones: vec![],
            format_version: 1,
            total_bytes: 100000,
            protocol_version: 4,
        };

        let bytes = state_writer::tests::serialize_for_test(&manifest);
        let parsed = state_reader::parse_state_manifest(&bytes).unwrap();

        let bounds = parsed.manifests[0].partition_bounds.as_ref().unwrap();
        assert_eq!(bounds.min_values.get("date"), Some(&"2024-01-01".to_string()));
        assert_eq!(bounds.max_values.get("date"), Some(&"2024-12-31".to_string()));
    }

    // ========================================================================
    // 2. FileEntry Avro schema compatibility
    // ========================================================================

    #[test]
    fn test_file_entry_schema_matches_scala() {
        let schema = schemas::file_entry_schema();
        match &schema {
            apache_avro::Schema::Record(r) => {
                assert_eq!(r.name.fullname(None), "io.indextables.state.FileEntry");

                // Verify key Scala fields are present
                let field_names: Vec<&str> = r.fields.iter()
                    .map(|f| f.name.as_str())
                    .collect();

                // Required Scala fields
                assert!(field_names.contains(&"path"));
                assert!(field_names.contains(&"partitionValues"));
                assert!(field_names.contains(&"size"));
                assert!(field_names.contains(&"modificationTime"));
                assert!(field_names.contains(&"dataChange"));
                assert!(field_names.contains(&"hasFooterOffsets"));
                assert!(field_names.contains(&"splitTags"));
                assert!(field_names.contains(&"numMergeOps"));
                assert!(field_names.contains(&"docMappingRef"));
                assert!(field_names.contains(&"uncompressedSizeBytes"));
                assert!(field_names.contains(&"addedAtVersion"));
                assert!(field_names.contains(&"addedAtTimestamp"));
                assert!(field_names.contains(&"companionSourceFiles"));

                // Extension fields kept for roundtrip compat
                // (Scala ignores unknown fields via schema evolution)
                assert!(field_names.contains(&"deleteOpstamp"));
                assert!(field_names.contains(&"docMappingJson"));
                assert!(field_names.contains(&"timeRangeStart"));
                assert!(field_names.contains(&"timeRangeEnd"));
            }
            _ => panic!("Expected Record schema"),
        }
    }

    #[test]
    fn test_file_entry_avro_roundtrip() {
        let entries = vec![
            make_file_entry("splits/file1.split", 1, 10000),
            make_file_entry("splits/file2.split", 2, 20000),
        ];

        let bytes = manifest_writer::write_manifest_bytes(&entries).unwrap();

        // Must be Avro binary
        assert_eq!(&bytes[0..4], b"Obj\x01");

        let parsed = manifest_reader::read_manifest_bytes(&bytes).unwrap();
        assert_eq!(parsed.len(), 2);
        assert_eq!(parsed[0].add.path, "splits/file1.split");
        assert_eq!(parsed[0].add.size, 10000);
        assert_eq!(parsed[0].added_at_version, 1);
        assert_eq!(parsed[1].add.path, "splits/file2.split");
        assert_eq!(parsed[1].added_at_version, 2);
    }

    #[test]
    fn test_file_entry_with_all_optional_fields() {
        let mut entry = make_file_entry("splits/full.split", 5, 50000);
        entry.add.stats = Some(r#"{"numRecords":100}"#.to_string());
        entry.add.min_values = Some({
            let mut m = HashMap::new();
            m.insert("id".to_string(), "1".to_string());
            m
        });
        entry.add.max_values = Some({
            let mut m = HashMap::new();
            m.insert("id".to_string(), "999".to_string());
            m
        });
        entry.add.num_records = Some(100);
        entry.add.footer_start_offset = Some(45000);
        entry.add.footer_end_offset = Some(50000);
        entry.add.has_footer_offsets = Some(true);
        entry.add.split_tags = Some(vec!["tag1".to_string(), "tag2".to_string()]);
        entry.add.num_merge_ops = Some(3);
        entry.add.doc_mapping_ref = Some("abc123hash".to_string());
        entry.add.uncompressed_size_bytes = Some(75000);
        entry.add.companion_source_files = Some(vec!["data/file1.parquet".to_string()]);
        entry.add.companion_delta_version = Some(42);
        entry.add.companion_fast_field_mode = Some("HYBRID".to_string());

        let bytes = manifest_writer::write_manifest_bytes(&[entry]).unwrap();
        let parsed = manifest_reader::read_manifest_bytes(&bytes).unwrap();

        assert_eq!(parsed.len(), 1);
        let p = &parsed[0];
        assert_eq!(p.add.stats.as_deref(), Some(r#"{"numRecords":100}"#));
        assert_eq!(p.add.footer_start_offset, Some(45000));
        assert_eq!(p.add.has_footer_offsets, Some(true));
        assert_eq!(p.add.split_tags.as_ref().unwrap().len(), 2);
        assert_eq!(p.add.num_merge_ops, Some(3));
        assert_eq!(p.add.doc_mapping_ref.as_deref(), Some("abc123hash"));
        assert_eq!(p.add.companion_fast_field_mode.as_deref(), Some("HYBRID"));
    }

    // ========================================================================
    // 3. _last_checkpoint JSON format
    // ========================================================================

    #[test]
    fn test_last_checkpoint_json_format() {
        let info = LastCheckpointInfo {
            version: 42,
            size: 1000,
            size_in_bytes: 50000,
            num_files: 1000,
            created_time: 1700000000000,
            format: Some("avro-state".to_string()),
            state_dir: Some("state-v00000000000000000042".to_string()),
            parts: None,
            checkpoint_id: None,
        };

        let json = serde_json::to_string(&info).unwrap();
        let parsed: serde_json::Value = serde_json::from_str(&json).unwrap();

        // Verify all required fields are present (matching Scala)
        assert_eq!(parsed["version"], 42);
        assert_eq!(parsed["size"], 1000);
        assert_eq!(parsed["sizeInBytes"], 50000);
        assert_eq!(parsed["numFiles"], 1000);
        assert_eq!(parsed["createdTime"], 1700000000000i64);
        assert_eq!(parsed["format"], "avro-state");
        assert_eq!(parsed["stateDir"], "state-v00000000000000000042");

        // Optional fields should not be present when None
        assert!(parsed.get("parts").is_none() || parsed["parts"].is_null());
        assert!(parsed.get("checkpointId").is_none() || parsed["checkpointId"].is_null());
    }

    #[test]
    fn test_last_checkpoint_roundtrip() {
        let info = LastCheckpointInfo {
            version: 100,
            size: 5000,
            size_in_bytes: 250000,
            num_files: 5000,
            created_time: 1700000000000,
            format: Some("avro-state".to_string()),
            state_dir: Some("state-v00000000000000000100".to_string()),
            parts: None,
            checkpoint_id: None,
        };

        let json = serde_json::to_vec(&info).unwrap();
        let parsed: LastCheckpointInfo = serde_json::from_slice(&json).unwrap();

        assert_eq!(parsed.version, 100);
        assert_eq!(parsed.size_in_bytes, 250000);
        assert_eq!(parsed.num_files, 5000);
        assert_eq!(parsed.created_time, 1700000000000);
        assert_eq!(parsed.format, Some("avro-state".to_string()));
    }

