    // ========================================================================

    #[test]
    fn test_protocol_version_persisted() {
        let manifest = StateManifest {
            version: 1,
            manifests: vec![],
            partition_bounds: None,
            created_time: 1700000000000,
            total_file_count: 0,
            format: "avro-state".to_string(),
            protocol_json: None,
            metadata: None,
            schema_registry: HashMap::new(),
            tombstones: vec![],
            format_version: 1,
            total_bytes: 0,
            protocol_version: 4,
        };

        let bytes = state_writer::tests::serialize_for_test(&manifest);
        let parsed = state_reader::parse_state_manifest(&bytes).unwrap();
        assert_eq!(parsed.protocol_version, 4);

        // protocol_json should be reconstructed from protocol_version
        let protocol_json = parsed.protocol_json.as_ref().unwrap();
        let protocol: ProtocolAction = serde_json::from_str(protocol_json).unwrap();
        assert_eq!(protocol.min_reader_version, 4);
        assert_eq!(protocol.min_writer_version, 4);
    }

    // ========================================================================
    // Scala-generated fixture reading tests
    //
    // These read actual transaction logs generated by Scala v0.5.4 and validate
    // that the Rust reader can parse every component correctly.
    // ========================================================================

    const FIXTURE_BASE: &str = concat!(env!("CARGO_MANIFEST_DIR"), "/src/txlog/test_fixtures/indextables_spark_v0.5.4");

    fn fixture_path(name: &str) -> String {
        format!("{}/{}", FIXTURE_BASE, name)
    }

    fn read_fixture_last_checkpoint(name: &str) -> Option<LastCheckpointInfo> {
        let path = format!("{}/_transaction_log/_last_checkpoint", fixture_path(name));
        let data = std::fs::read(&path).ok()?;
        serde_json::from_slice(&data).ok()
    }

    fn read_fixture_state_manifest(name: &str, state_dir: &str) -> StateManifest {
        let path = format!("{}/_transaction_log/{}/{}", fixture_path(name), state_dir, STATE_MANIFEST_FILENAME);
        let data = std::fs::read(&path).expect(&format!("Failed to read {}", path));
        state_reader::parse_state_manifest(&data).expect(&format!("Failed to parse {}", path))
    }

    fn read_fixture_manifest_avro(name: &str, manifest_path: &str) -> Vec<FileEntry> {
        let full_path = format!("{}/_transaction_log/{}", fixture_path(name), manifest_path);
        let data = std::fs::read(&full_path).expect(&format!("Failed to read {}", full_path));
        manifest_reader::read_manifest_bytes(&data).expect(&format!("Failed to parse {}", full_path))
    }

    fn fixture_exists(name: &str) -> bool {
        std::path::Path::new(&fixture_path(name)).exists()
    }

