    // --- 06: Schema dedup ---

    #[test]
    fn test_scala_fixture_06_schema_dedup() {
        if !fixture_exists("06_schema_dedup") { return; }
        let cp = read_fixture_last_checkpoint("06_schema_dedup").unwrap();
        let state_dir = cp.state_dir.unwrap();
        let manifest = read_fixture_state_manifest("06_schema_dedup", &state_dir);

        // Should have schema registry entries
        assert!(!manifest.schema_registry.is_empty(),
            "schema dedup fixture should have schema registry entries");

        // Schema registry keys are the raw hash values (16-char Base64)
        for key in manifest.schema_registry.keys() {
            // Keys may be raw hashes or prefixed with docMappingSchema.
            assert!(key.len() >= 16 || key.starts_with("docMappingSchema."),
                "schema registry key should be a hash or prefixed: {}", key);
        }

        // Read entries and verify docMappingRef is populated
        let mut has_ref = false;
        for mi in &manifest.manifests {
            let resolved = state_reader::resolve_manifest_path(&state_dir, &mi.path);
            let entries = read_fixture_manifest_avro("06_schema_dedup", &resolved);
            for entry in &entries {
                if entry.add.doc_mapping_ref.is_some() {
                    has_ref = true;
                    let ref_key = entry.add.doc_mapping_ref.as_ref().unwrap();
                    assert_eq!(ref_key.len(), 16, "docMappingRef should be 16-char hash");
                    // Verify ref exists in registry (may be prefixed or raw)
                    let prefixed_key = format!("docMappingSchema.{}", ref_key);
                    let in_registry = manifest.schema_registry.contains_key(&prefixed_key)
                        || manifest.schema_registry.contains_key(ref_key);
                    assert!(in_registry,
                        "docMappingRef {} should exist in schema registry", ref_key);
                }
            }
        }
        assert!(has_ref, "schema dedup fixture should have entries with docMappingRef");
    }

    // --- 12: Partition drop ---

    #[test]
    fn test_scala_fixture_12_partition_drop() {
        if !fixture_exists("12_partition_drop") { return; }
        let cp = read_fixture_last_checkpoint("12_partition_drop").unwrap();
        let state_dir = cp.state_dir.unwrap();
        let manifest = read_fixture_state_manifest("12_partition_drop", &state_dir);

        // After dropping date=2024-01-02, should have tombstones or fewer files
        // Read all entries and apply tombstones
        let mut all_entries = Vec::new();
        for mi in &manifest.manifests {
            let resolved = state_reader::resolve_manifest_path(&state_dir, &mi.path);
            let entries = read_fixture_manifest_avro("12_partition_drop", &resolved);
            all_entries.extend(entries);
        }

        // Apply tombstones
        if !manifest.tombstones.is_empty() {
            let tombstone_set: HashSet<&str> = manifest.tombstones.iter().map(|s| s.as_str()).collect();
            all_entries.retain(|e| !tombstone_set.contains(e.add.path.as_str()));
        }

        // Should have fewer live files than original 6 (dropped date=2024-01-02)
        assert!(all_entries.len() < 6 && all_entries.len() >= 1,
            "after partition drop, should have fewer than 6 live files, got {}", all_entries.len());

        // None of the remaining should be from the dropped partition
        for entry in &all_entries {
            let date = entry.add.partition_values.get("date");
            assert_ne!(date, Some(&"2024-01-02".to_string()),
                "dropped partition date=2024-01-02 should not appear in live entries");
        }
    }

