    /// Read a version file from a fixture (parse_version_file handles decompression internally)
    fn read_fixture_version_file(name: &str, version: i64) -> Vec<Action> {
        let version_path = format!("{}/_transaction_log/{}",
            fixture_path(name),
            TxLogStorage::version_path(version));
        let data = std::fs::read(&version_path)
            .expect(&format!("Failed to read {}", version_path));
        crate::txlog::version_file::parse_version_file(&data)
            .expect("parse failed")
    }

    /// Get all live entries from a fixture (state manifest + tombstone filtering)
    fn get_live_entries(name: &str) -> (StateManifest, Vec<FileEntry>) {
        let cp = read_fixture_last_checkpoint(name).unwrap();
        let state_dir = cp.state_dir.unwrap();
        let manifest = read_fixture_state_manifest(name, &state_dir);
        let mut all_entries = Vec::new();
        for mi in &manifest.manifests {
            let resolved = state_reader::resolve_manifest_path(&state_dir, &mi.path);
            let entries = read_fixture_manifest_avro(name, &resolved);
            all_entries.extend(entries);
        }
        // Apply tombstones
        if !manifest.tombstones.is_empty() {
            let tombstone_set: HashSet<&str> = manifest.tombstones.iter()
                .map(|s| s.as_str()).collect();
            all_entries.retain(|e| !tombstone_set.contains(e.add.path.as_str()));
        }
        (manifest, all_entries)
    }

