    // Fixture 02: Five appends — shared manifest reuse
    // ========================================================================

    #[test]
    fn test_scala_fixture_02_shared_manifest_reuse() {
        if !fixture_exists("02_five_appends") { return; }
        let cp = read_fixture_last_checkpoint("02_five_appends").unwrap();
        let state_dir = cp.state_dir.unwrap();
        let manifest = read_fixture_state_manifest("02_five_appends", &state_dir);

        // Should reference multiple shared manifests
        assert!(manifest.manifests.len() >= 2,
            "five appends should produce multiple shared manifests, got {}",
            manifest.manifests.len());

        // All manifest paths should start with manifests/
        for mi in &manifest.manifests {
            assert!(mi.path.starts_with("manifests/"),
                "shared manifest path should start with manifests/: {}", mi.path);
        }

        // Verify version tracking - manifests should have valid version ranges
        for mi in &manifest.manifests {
            assert!(mi.max_added_at_version >= mi.min_added_at_version,
                "max_added_at_version ({}) should be >= min ({})",
                mi.max_added_at_version, mi.min_added_at_version);
        }

        // Verify total entry count matches sum of manifest file_count values
        let sum_file_count: i64 = manifest.manifests.iter()
            .map(|mi| mi.file_count).sum();
        assert_eq!(manifest.total_file_count, sum_file_count,
            "total_file_count ({}) should match sum of manifest file_counts ({})",
            manifest.total_file_count, sum_file_count);

        // Read all entries, verify there are entries from five appends
        let (_, entries) = get_live_entries("02_five_appends");
        assert_eq!(entries.len() as i64, manifest.total_file_count,
            "entry count should match total_file_count");
        assert!(entries.len() >= 5,
            "five appends should produce at least 5 entries, got {}", entries.len());
    }

