    #[test]
    fn test_scala_fixture_09_streaming_version_filter() {
        if !fixture_exists("09_partitioned_multi_append") { return; }
        let cp = read_fixture_last_checkpoint("09_partitioned_multi_append").unwrap();
        let state_dir = cp.state_dir.unwrap();
        let manifest = read_fixture_state_manifest("09_partitioned_multi_append", &state_dir);

        use crate::txlog::streaming;

        // Filter with since_version=0 should return all manifests
        let all = streaming::filter_manifests_by_version(&manifest.manifests, 0);
        assert_eq!(all.len(), manifest.manifests.len(),
            "since_version=0 should return all manifests");

        // Filter with a high version should return fewer or no manifests
        let high_version = manifest.version + 100;
        let none = streaming::filter_manifests_by_version(&manifest.manifests, high_version);
        assert!(none.is_empty() || none.iter().all(|m| m.max_added_at_version == 0),
            "since_version beyond latest should return no manifests (or only unknown-version ones)");

        // Filter for version=1 should return at least the manifest containing v1 entries
        let v1 = streaming::filter_manifests_for_version(&manifest.manifests, 1);
        assert!(!v1.is_empty(),
            "filter_manifests_for_version(1) should find at least one manifest");
    }

