    #[test]
    fn test_scala_fixture_16_skip_actions_readable() {
        if !fixture_exists("16_with_skip_actions") { return; }

        // Read the fixture state and verify it has valid structure
        let cp = read_fixture_last_checkpoint("16_with_skip_actions").unwrap();
        let state_dir = cp.state_dir.unwrap();
        let manifest = read_fixture_state_manifest("16_with_skip_actions", &state_dir);

        assert!(manifest.total_file_count >= 1,
            "skip actions fixture should have entries");
        assert_eq!(manifest.protocol_version, 4);

        // Scan version files for MergeSkip actions if they exist
        let mut found_skip = false;
        for version in 0..20 {
            let version_path = format!("{}/_transaction_log/{}",
                fixture_path("16_with_skip_actions"),
                TxLogStorage::version_path(version));
            if !std::path::Path::new(&version_path).exists() {
                continue;
            }
            let actions = read_fixture_version_file("16_with_skip_actions", version);
            for action in &actions {
                if let Action::MergeSkip(skip) = action {
                    found_skip = true;
                    assert!(!skip.path.is_empty(),
                        "skip action should have a path");
                    assert!(skip.skip_timestamp > 0,
                        "skip action should have a positive timestamp");
                }
            }
        }
        // Skip actions may only appear in version files that were not checkpointed,
        // or they may be encoded differently in the Scala implementation.
        // If found, verify them; otherwise just confirm the fixture is readable.
        if !found_skip {
            // Verify entries are readable even without explicit skip actions in version files
            let (_, entries) = get_live_entries("16_with_skip_actions");
            assert!(!entries.is_empty(),
                "skip actions fixture should have live entries");
        }
    }

