    #[test]
    fn test_footer_offsets_scan_across_fixtures() {
        let fixtures = [
            "01_single_write", "02_five_appends", "04_partitioned",
            "05_many_transactions", "10_large_batch", "14_after_merge",
        ];

        let mut found_footer_offsets = false;
        for fixture_name in &fixtures {
            if !fixture_exists(fixture_name) { continue; }
            let (_, entries) = get_live_entries(fixture_name);
            for entry in &entries {
                if entry.add.footer_start_offset.is_some()
                    || entry.add.footer_end_offset.is_some()
                {
                    found_footer_offsets = true;
                    // If footer offsets are present, hasFooterOffsets should be true
                    if let Some(has) = entry.add.has_footer_offsets {
                        assert!(has,
                            "has_footer_offsets should be true when footer offsets are populated: {}",
                            entry.add.path);
                    }
                    // Start should be < end
                    if let (Some(start), Some(end)) = (entry.add.footer_start_offset, entry.add.footer_end_offset) {
                        assert!(start < end,
                            "footer_start_offset ({}) should be < footer_end_offset ({}): {}",
                            start, end, entry.add.path);
                    }
                }
            }
        }
        // Footer offsets may not be present in basic fixtures - not an error
        if !found_footer_offsets {
            // Informational: no footer offsets found across scanned fixtures
        }
    }

