    // ========================================================================
    // Comprehensive fixture existence and readability test
    // ========================================================================

    #[test]
    fn test_all_16_fixtures_readable() {
        let fixtures = [
            "01_single_write", "02_five_appends", "03_with_removes",
            "04_partitioned", "05_many_transactions", "06_schema_dedup",
            "07_two_writes_no_checkpoint", "08_ten_writes_at_checkpoint",
            "09_partitioned_multi_append", "10_large_batch",
            "11_mixed_operations", "12_partition_drop",
            "13_after_purge", "14_after_merge",
            "15_drop_then_purge", "16_with_skip_actions",
        ];

        let mut readable_count = 0;
        for fixture_name in &fixtures {
            if !fixture_exists(fixture_name) {
                continue;
            }
            readable_count += 1;

            // Every fixture should have a valid checkpoint
            let cp = read_fixture_last_checkpoint(fixture_name)
                .expect(&format!("{}: should have _last_checkpoint", fixture_name));
            assert!(cp.version >= 0,
                "{}: checkpoint version should be >= 0", fixture_name);
            assert_eq!(cp.format, Some("avro-state".to_string()),
                "{}: checkpoint format should be avro-state", fixture_name);

            // Every fixture should have a readable state manifest
            let state_dir = cp.state_dir
                .expect(&format!("{}: checkpoint should have stateDir", fixture_name));
            let manifest = read_fixture_state_manifest(fixture_name, &state_dir);
            assert_eq!(manifest.format_version, 1,
                "{}: format_version should be 1", fixture_name);
            assert_eq!(manifest.protocol_version, 4,
                "{}: protocol_version should be 4", fixture_name);

            // Every fixture should have version 0 with protocol + metadata
            let v0_path = format!("{}/_transaction_log/{}",
                fixture_path(fixture_name),
                TxLogStorage::version_path(0));
            if std::path::Path::new(&v0_path).exists() {
                let actions = read_fixture_version_file(fixture_name, 0);
                assert!(actions.iter().any(|a| matches!(a, Action::Protocol(_))),
                    "{}: version 0 should have ProtocolAction", fixture_name);
                assert!(actions.iter().any(|a| matches!(a, Action::MetaData(_))),
                    "{}: version 0 should have MetadataAction", fixture_name);
            }
        }

        assert_eq!(readable_count, 16,
            "all 16 fixtures should exist and be readable, only found {}", readable_count);
    }

    // ========================================================================
    // All manifest entries readable across all fixtures
    // ========================================================================

    #[test]
    fn test_all_fixture_manifest_entries_readable() {
        let fixtures = [
            "01_single_write", "02_five_appends", "03_with_removes",
            "04_partitioned", "05_many_transactions", "06_schema_dedup",
            "07_two_writes_no_checkpoint", "08_ten_writes_at_checkpoint",
            "09_partitioned_multi_append", "10_large_batch",
            "11_mixed_operations", "12_partition_drop",
            "13_after_purge", "14_after_merge",
            "15_drop_then_purge", "16_with_skip_actions",
        ];

        for fixture_name in &fixtures {
            if !fixture_exists(fixture_name) { continue; }
            let cp = read_fixture_last_checkpoint(fixture_name).unwrap();
            let state_dir = cp.state_dir.unwrap();
            let manifest = read_fixture_state_manifest(fixture_name, &state_dir);

            let mut total_read = 0;
            for mi in &manifest.manifests {
                let resolved = state_reader::resolve_manifest_path(&state_dir, &mi.path);
                let entries = read_fixture_manifest_avro(fixture_name, &resolved);
                assert_eq!(entries.len() as i64, mi.file_count,
                    "{}: manifest {} file_count ({}) should match entries read ({})",
                    fixture_name, mi.path, mi.file_count, entries.len());

                for entry in &entries {
                    assert!(!entry.add.path.is_empty(),
                        "{}: entry should have non-empty path", fixture_name);
                    assert!(entry.add.size >= 0,
                        "{}: entry size should be non-negative", fixture_name);
                    assert!(entry.added_at_version >= 0,
                        "{}: added_at_version should be >= 0", fixture_name);
                }
                total_read += entries.len();
            }

            // After applying tombstones, live count should match
            let tombstone_set: HashSet<&str> = manifest.tombstones.iter()
                .map(|s| s.as_str()).collect();
            let live_count = if tombstone_set.is_empty() {
                total_read
            } else {
                // Re-read and filter
                let mut live = 0;
                for mi in &manifest.manifests {
                    let resolved = state_reader::resolve_manifest_path(&state_dir, &mi.path);
                    let entries = read_fixture_manifest_avro(fixture_name, &resolved);
                    live += entries.iter()
                        .filter(|e| !tombstone_set.contains(e.add.path.as_str()))
                        .count();
                }
                live
            };

            assert_eq!(live_count as i64, manifest.total_file_count,
                "{}: live entry count ({}) should match total_file_count ({})",
                fixture_name, live_count, manifest.total_file_count);
        }
    }

    // --- 17: Truncated log (post-TRUNCATE TIME TRAVEL) ---

    #[test]
    fn test_scala_fixture_17_truncated_log_self_contained() {
        if !fixture_exists("17_truncated_log") { return; }
        let cp = read_fixture_last_checkpoint("17_truncated_log").unwrap();
        let state_dir = cp.state_dir.unwrap();
        let manifest = read_fixture_state_manifest("17_truncated_log", &state_dir);

        // After truncation, the checkpoint must be self-contained:
        // - protocol_version should be populated
        // - metadata field should contain the MetadataAction JSON (if present)
        assert_eq!(manifest.protocol_version, 4);

        // If metadata is cached, verify it's valid JSON
        if let Some(ref metadata_json) = manifest.metadata {
            let metadata: serde_json::Value = serde_json::from_str(metadata_json)
                .expect("cached metadata should be valid JSON");
            // MetadataAction has id and schemaString fields
            assert!(metadata.is_object(), "metadata should be a JSON object");
        }

        // Should still be able to read all file entries
        let mut total_entries = 0;
        for mi in &manifest.manifests {
            let resolved = state_reader::resolve_manifest_path(&state_dir, &mi.path);
            let entries = read_fixture_manifest_avro("17_truncated_log", &resolved);
            total_entries += entries.len();
        }
        assert!(total_entries >= 1, "should have readable entries even after truncation");
    }
